from typing import Literal, Final, Callable

MODE: Final = "r"                       # constant; reassignment is flagged

def open_file(path: str, mode: Literal["r", "w", "a"]) -> str:
    return f"opened {path!r} in mode {mode}"

# Callable[[arg types], return type]
def apply(fn: Callable[[int], int], value: int) -> int:
    return fn(value)

print(open_file("data.txt", "r"))
print(apply(lambda x: x * 2, 21))      # 42
# open_file("x", "rw")  # checker error: "rw" not a valid Literal

from typing import TypedDict, Protocol

class User(TypedDict):
    name: str
    age: int

def describe(u: User) -> str:
    return f"{u['name']} ({u['age']})"

class Readable(Protocol):
    def read(self) -> str: ...

# Anything with a matching .read() satisfies Readable — no inheritance.
def load(src: Readable) -> str:
    return src.read()

print(describe({"name": "Ada", "age": 36}))

