# test_account.py  (run with: python -m unittest)
import unittest

class Account:
    def __init__(self, balance: float = 0.0) -> None:
        self.balance = balance
    def withdraw(self, amount: float) -> None:
        if amount > self.balance:
            raise ValueError("insufficient funds")
        self.balance -= amount

class TestAccount(unittest.TestCase):
    def setUp(self) -> None:           # runs before EACH test
        self.acct = Account(100.0)

    def test_withdraw_ok(self) -> None:
        self.acct.withdraw(40)
        self.assertEqual(self.acct.balance, 60.0)

    def test_overdraw_raises(self) -> None:
        with self.assertRaises(ValueError):
            self.acct.withdraw(999)

if __name__ == "__main__":
    unittest.main()

import unittest
from unittest.mock import Mock

def get_user_name(client) -> str:
    return client.fetch()["name"].upper()

class TestUser(unittest.TestCase):
    def test_uses_client(self) -> None:
        # Replace the real client with a Mock that returns canned data
        client = Mock()
        client.fetch.return_value = {"name": "ada"}

        self.assertEqual(get_user_name(client), "ADA")
        client.fetch.assert_called_once()   # verify the call happened

if __name__ == "__main__":
    unittest.main()

def make_user(name: str) -> dict:
    """Build a user record.

    Use +ELLIPSIS so the variable id can be matched with ...

    >>> make_user("ada")  # doctest: +ELLIPSIS
    {'name': 'ada', 'id': ...}
    """
    import random
    return {"name": name, "id": random.randint(1, 9999)}
